#include <bits/stdc++.h>
using namespace std;
const int maxn=305,kd[][2]={1,0,-1,0,0,1,0,-1};
struct Node{
	int x,y,t;
};
int m,dis[maxn][maxn],vis[maxn][maxn];
queue<Node> q;
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>m;
	fill(dis[0],dis[300+2],-1);
	for(int i=1,x,y,t;i<=m;i++){
		cin>>x>>y>>t;
		if(t<dis[x][y]||dis[x][y]==-1){
			dis[x][y]=t;
		}
		for(int j=0;j<4;j++){
			int nx=x+kd[j][0],ny=y+kd[j][1];
			if(nx>=0&&ny>=0&&(dis[nx][ny]==-1||t<dis[nx][ny])){
				dis[nx][ny]=t;
			}
		}
	}
	Node qd={0,0,0};
	vis[0][0]=1;
	q.push(qd);
	while(q.size()){
		Node p=q.front();
		q.pop();
		if(dis[p.x][p.y]==-1){
			cout<<p.t<<"\n";
			return 0;
		}
		for(int i=0;i<4;i++){
			int nx=p.x+kd[i][0],ny=p.y+kd[i][1];
			if(nx>=0&&ny>=0&&vis[nx][ny]==0&&(dis[nx][ny]==-1||p.t+1<dis[nx][ny])){
				q.push({nx,ny,p.t+1}),vis[nx][ny]=1;
			}
		}
	}
	cout<<-1;
	return 0;
}
